            }
            CrcProbe::Missing => self.create_current_backup(row, current_backup_path),
            CrcProbe::Unreadable { safe_message } => {
                Err(format!("{} {}", BACKUP_READ_FAILURE_MESSAGE, safe_message))
            }
        }
    }

