//! Slint-free Downgrader modal controller and worker-payload reducer.
//!
//! The controller owns modal lifecycle state, request ids, selected target,
//! backup/delta options, inline plan confirmation state, progress, and visible
//! log rows. It performs no filesystem, network, xdelta, settings persistence,
//! or Slint work. Production UI code should schedule the returned worker
//! requests off the event loop and feed owned worker events back through this
//! reducer.

use crate::{
    domain::{
        discovery::Fallout4Installation,
        downgrader::{
            DELETE_PATCHES_CHECKBOX_LABEL, DowngraderExecutionLogRow, DowngraderLogLevel,
            DowngraderOptionsSnapshot, DowngraderProgress, DowngraderTarget,
            KEEP_BACKUPS_CHECKBOX_LABEL,
        },
        settings::{DowngraderSettings, DOWNGRADER_DELETE_DELTAS_KEY, DOWNGRADER_KEEP_BACKUPS_KEY},
    },
    services::downgrader::{
        DowngraderExecutionResult, DowngraderPreviewPlan, DowngraderStatusSnapshot,
    },
    workers::{
        DowngraderWorkerPayload, DowngraderWorkerStage, WorkerEvent, WorkerFailure,
        WorkerPayload, WorkerSpawnError, WorkerTask, WorkerTaskId, WorkerTaskKind,
        WorkerTaskStatus,
    },
};

/// Stable prefix for S09 Downgrader status worker task identifiers.
pub const DOWNGRADER_STATUS_TASK_PREFIX: &str = "s09-downgrader-status:";
/// Stable prefix for S09 Downgrader preview-plan worker task identifiers.
pub const DOWNGRADER_PLAN_TASK_PREFIX: &str = "s09-downgrader-plan:";
/// Stable prefix for S09 Downgrader confirmed-run worker task identifiers.
pub const DOWNGRADER_RUN_TASK_PREFIX: &str = "s09-downgrader-run:";

/// Safe text shown while the modal is loading current file status.
pub const DOWNGRADER_LOADING_STATUS_MESSAGE: &str = "Loading Downgrader status...";
/// Safe text shown while the inline confirmation plan is being prepared.
pub const DOWNGRADER_PLANNING_MESSAGE: &str = "Preparing downgrade plan...";
/// Safe text shown once the inline plan is ready for explicit confirmation.
pub const DOWNGRADER_PLAN_READY_MESSAGE: &str = "Review the plan, then click Patch All again to confirm.";
/// Safe text shown while confirmed patching is running.
pub const DOWNGRADER_RUNNING_MESSAGE: &str = "Patching...";
/// Safe text shown after the confirmed worker completes.
pub const DOWNGRADER_COMPLETED_MESSAGE: &str = "Patching complete.";
/// Safe text shown when a status worker cannot be scheduled.
pub const DOWNGRADER_STATUS_START_FAILED_MESSAGE: &str = "Downgrader status could not be started.";
/// Safe text shown when a plan worker cannot be scheduled.
pub const DOWNGRADER_PLAN_START_FAILED_MESSAGE: &str = "Downgrader plan could not be started.";
/// Safe text shown when a run worker cannot be scheduled.
pub const DOWNGRADER_RUN_START_FAILED_MESSAGE: &str = "Downgrader patching could not be started.";
/// Safe text shown when patching is requested before status is ready.
pub const DOWNGRADER_PATCH_UNAVAILABLE_MESSAGE: &str = "Downgrader patching is not available yet.";
/// Safe text shown when an inline plan failed and cannot be confirmed.
pub const DOWNGRADER_PLAN_NOT_EXECUTABLE_MESSAGE: &str = "Downgrader plan cannot be executed.";

/// Monotonic identity assigned to each Downgrader worker request.
pub type DowngraderRequestId = u64;

/// Render-relevant lifecycle state for the Downgrader modal.
#[derive(Debug, Default, Clone, Copy, PartialEq, Eq, Hash)]
pub enum DowngraderControllerPhase {
    /// The modal is closed and no worker result should be applied.
    #[default]
    Closed,
    /// The modal is visible while current file status is loading.
    LoadingStatus,
    /// Status is loaded and the first `Patch All` click will request a plan.
    Ready,
    /// A read-only inline plan worker is active.
    Planning,
    /// A read-only inline plan is visible and requires a second explicit click.
    PlanReady,
    /// A confirmed patch run is active; close/Escape must be blocked.
    Running,
    /// A confirmed patch run completed and patching can be requested again.
    Completed,
    /// A safe user-visible error is shown and close is allowed.
    SafeError,
}

/// Result of applying a Downgrader controller transition.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
pub enum DowngraderTransitionResult {
    /// The event or intent matched current state and changed renderable data.
    Applied,
    /// The event belonged to an older request and was intentionally ignored.
    StaleIgnored,
    /// The event was not relevant to this reducer.
    Ignored,
    /// The intent was recognized but unavailable or malformed in current state.
    Rejected,
}

impl DowngraderTransitionResult {
    /// Returns true when the transition changed controller state.
    pub const fn is_applied(self) -> bool {
        matches!(self, Self::Applied)
    }
}

/// Result of a modal close/Escape request.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
pub enum DowngraderCloseResult {
    /// The modal was closed and active non-run requests were invalidated.
    Closed,
    /// The modal stayed open because a confirmed run is active.
    Blocked,
}

/// Owned worker request returned when opening the Downgrader modal.
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct DowngraderStatusWorkerRequest {
    /// Monotonic status request id used to reject stale worker results.
    pub request_id: DowngraderRequestId,
    /// Downgrader settings snapshot captured when the modal opened.
    pub settings_snapshot: DowngraderSettings,
    /// Optional discovered installation snapshot moved to the status worker.
    pub installation: Option<Fallout4Installation>,
    /// Worker task metadata that must accompany lifecycle events.
    pub task: WorkerTask,
}

impl DowngraderStatusWorkerRequest {
    /// Creates an owned status worker request.
    pub fn new(
        request_id: DowngraderRequestId,
        settings_snapshot: DowngraderSettings,
        installation: Option<Fallout4Installation>,
    ) -> Self {
        Self {
            request_id,
            settings_snapshot,
            installation,
            task: downgrader_status_task(request_id),
        }
    }
}

/// Owned worker request returned for the first `Patch All` click.
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct DowngraderPlanWorkerRequest {
    /// Monotonic plan request id used to reject stale worker results.
    pub request_id: DowngraderRequestId,
    /// Optional discovered installation snapshot moved to the plan worker.
    pub installation: Option<Fallout4Installation>,
    /// User-selected target and cleanup preferences captured at plan time.
    pub options: DowngraderOptionsSnapshot,
    /// Worker task metadata that must accompany lifecycle events.
    pub task: WorkerTask,
}

impl DowngraderPlanWorkerRequest {
    /// Creates an owned read-only plan worker request.
    pub fn new(
        request_id: DowngraderRequestId,
        installation: Option<Fallout4Installation>,
        options: DowngraderOptionsSnapshot,
    ) -> Self {
        Self {
            request_id,
            installation,
            options,
            task: downgrader_plan_task(request_id),
        }
    }
}

/// Owned worker request returned for the second confirmed `Patch All` click.
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct DowngraderRunWorkerRequest {
    /// Monotonic run request id used to reject stale worker results.
    pub request_id: DowngraderRequestId,
    /// Plan request id that the user explicitly confirmed.
    pub confirmed_plan_request_id: DowngraderRequestId,
    /// Optional discovered installation snapshot moved to the run worker.
    pub installation: Option<Fallout4Installation>,
    /// User-selected target and cleanup preferences captured at run time.
    pub options: DowngraderOptionsSnapshot,
    /// Worker task metadata that must accompany lifecycle events.
    pub task: WorkerTask,
}

impl DowngraderRunWorkerRequest {
    /// Creates an owned confirmed execution worker request.
    pub fn new(
        request_id: DowngraderRequestId,
        confirmed_plan_request_id: DowngraderRequestId,
        installation: Option<Fallout4Installation>,
        options: DowngraderOptionsSnapshot,
    ) -> Self {
        Self {
            request_id,
            confirmed_plan_request_id,
            installation,
            options,
            task: downgrader_run_task(request_id),
        }
    }
}

/// Worker request produced by a `Patch All` click.
#[derive(Debug, Clone, PartialEq, Eq)]
pub enum DowngraderPatchWorkerRequest {
    /// First click: prepare the read-only inline confirmation plan.
    PreviewPlan(DowngraderPlanWorkerRequest),
    /// Second click: execute the plan the user has already seen.
    ConfirmedRun(DowngraderRunWorkerRequest),
}

/// Pure reducer for Downgrader modal UI state and owned worker events.
#[derive(Debug, Clone, PartialEq)]
pub struct DowngraderController {
    phase: DowngraderControllerPhase,
    next_request_id: DowngraderRequestId,
    active_status_request_id: Option<DowngraderRequestId>,
    active_plan_request_id: Option<DowngraderRequestId>,
    active_run_request_id: Option<DowngraderRequestId>,
    latest_plan_request_id: Option<DowngraderRequestId>,
    installation: Option<Fallout4Installation>,
    settings_snapshot: DowngraderSettings,
    options: DowngraderOptionsSnapshot,
    status: Option<DowngraderStatusSnapshot>,
    plan: Option<DowngraderPreviewPlan>,
    log_rows: Vec<DowngraderExecutionLogRow>,
    run_log_row_count: usize,
    progress: DowngraderProgress,
    status_text: String,
    safe_error: Option<String>,
    pending_status_refresh: Option<DowngraderStatusWorkerRequest>,
}

impl Default for DowngraderController {
    fn default() -> Self {
        Self::new()
    }
}

impl DowngraderController {
    /// Creates a closed Downgrader controller with reference default options.
    pub fn new() -> Self {
        let settings = DowngraderSettings::default();
        Self {
            phase: DowngraderControllerPhase::Closed,
            next_request_id: 1,
            active_status_request_id: None,
            active_plan_request_id: None,
            active_run_request_id: None,
            latest_plan_request_id: None,
            installation: None,
            settings_snapshot: settings.clone(),
            options: options_from_settings(&settings, DowngraderTarget::OldGen),
            status: None,
            plan: None,
            log_rows: Vec::new(),
            run_log_row_count: 0,
            progress: DowngraderProgress::idle(),
            status_text: String::new(),
            safe_error: None,
            pending_status_refresh: None,
        }
    }

    /// Returns the current modal lifecycle phase.
    pub const fn phase(&self) -> DowngraderControllerPhase {
        self.phase
    }

    /// Returns whether the modal should be visible.
    pub const fn is_open(&self) -> bool {
        !matches!(self.phase, DowngraderControllerPhase::Closed)
    }

    /// Returns the next monotonic request id that will be assigned.
    pub const fn next_request_id(&self) -> DowngraderRequestId {
        self.next_request_id
    }

    /// Returns the active status request id, if a status worker result is expected.
    pub const fn active_status_request_id(&self) -> Option<DowngraderRequestId> {
        self.active_status_request_id
    }

    /// Returns the active plan request id, if a plan worker result is expected.
    pub const fn active_plan_request_id(&self) -> Option<DowngraderRequestId> {
        self.active_plan_request_id
    }

    /// Returns the active run request id, if a confirmed run is active.
    pub const fn active_run_request_id(&self) -> Option<DowngraderRequestId> {
        self.active_run_request_id
    }

    /// Returns the current target and cleanup options.
    pub const fn options(&self) -> DowngraderOptionsSnapshot {
        self.options
    }

    /// Returns the current settings snapshot captured by the latest open request.
    pub const fn settings_snapshot(&self) -> &DowngraderSettings {
        &self.settings_snapshot
    }

    /// Returns the latest status snapshot, if status has loaded.
    pub fn status(&self) -> Option<&DowngraderStatusSnapshot> {
        self.status.as_ref()
    }

    /// Returns the latest inline preview plan, if one is awaiting confirmation.
    pub fn plan(&self) -> Option<&DowngraderPreviewPlan> {
        self.plan.as_ref()
    }

    /// Returns the visible modal log rows.
    pub fn log_rows(&self) -> &[DowngraderExecutionLogRow] {
        &self.log_rows
    }

    /// Returns the current progress-bar value.
    pub const fn progress(&self) -> DowngraderProgress {
        self.progress
    }

    /// Returns the current safe status text.
    pub fn status_text(&self) -> &str {
        self.status_text.as_str()
    }

    /// Returns the current safe error text, if any.
    pub fn safe_error(&self) -> Option<&str> {
        self.safe_error.as_deref()
    }

    /// Returns whether the `Patch All` action should be enabled.
    pub fn patch_button_enabled(&self) -> bool {
        match self.phase {
            DowngraderControllerPhase::Ready | DowngraderControllerPhase::Completed => {
                self.status.is_some()
            }
            DowngraderControllerPhase::PlanReady => self
                .plan
                .as_ref()
                .is_some_and(|plan| plan.can_execute && self.status.is_some()),
            DowngraderControllerPhase::Closed
            | DowngraderControllerPhase::LoadingStatus
            | DowngraderControllerPhase::Planning
            | DowngraderControllerPhase::Running
            | DowngraderControllerPhase::SafeError => false,
        }
    }

    /// Returns whether close/Escape should be allowed.
    pub const fn close_enabled(&self) -> bool {
        !matches!(self.phase, DowngraderControllerPhase::Running)
    }

    /// Opens the modal from the latest settings and installation snapshots.
    ///
    /// Opening schedules a status request and resets previous plan/run state. If
    /// a run is currently active, the request is rejected so close semantics stay
    /// fail-closed while file mutation may be in progress.
    pub fn open(
        &mut self,
        settings_snapshot: DowngraderSettings,
        installation: Option<Fallout4Installation>,
    ) -> Option<DowngraderStatusWorkerRequest> {
        if matches!(self.phase, DowngraderControllerPhase::Running) {
            tracing::warn!(
                event = "s09-downgrader-open-blocked-running",
                active_run_request_id = ?self.active_run_request_id,
                "Downgrader open request ignored because a run is active"
            );
            return None;
        }

        let request_id = self.allocate_request_id();
        self.phase = DowngraderControllerPhase::LoadingStatus;
        self.active_status_request_id = Some(request_id);
        self.active_plan_request_id = None;
        self.active_run_request_id = None;
        self.latest_plan_request_id = None;
        self.installation = installation.clone();
        self.settings_snapshot = settings_snapshot.clone();
        self.options = options_from_settings(&settings_snapshot, DowngraderTarget::OldGen);
        self.status = None;
        self.plan = None;
        self.log_rows = vec![DowngraderExecutionLogRow::initial()];
        self.run_log_row_count = 0;
        self.progress = DowngraderProgress::idle();
        self.status_text = DOWNGRADER_LOADING_STATUS_MESSAGE.to_owned();
        self.safe_error = None;
        self.pending_status_refresh = None;

        let request = DowngraderStatusWorkerRequest::new(request_id, settings_snapshot, installation);
        tracing::info!(
            event = "s09-downgrader-opened",
            request_id,
            task_id = %request.task.id,
            keep_backups = self.options.keep_backups,
            delete_deltas = self.options.delete_deltas,
            has_installation = self.installation.is_some(),
            "Downgrader modal opened and status requested"
        );
        Some(request)
    }

    /// Applies a status snapshot if it belongs to the active status request.
    pub fn status_loaded(
        &mut self,
        request_id: DowngraderRequestId,
        snapshot: DowngraderStatusSnapshot,
    ) -> DowngraderTransitionResult {
        if !self.is_active_request(DowngraderWorkerStage::Status, request_id)
            || snapshot.request_id != request_id
        {
            tracing::debug!(
                event = "s09-downgrader-status-stale-ignored",
                request_id,
                snapshot_request_id = snapshot.request_id,
                active_status_request_id = ?self.active_status_request_id,
                "Ignoring stale Downgrader status result"
            );
            return DowngraderTransitionResult::StaleIgnored;
        }

        let initial_load = matches!(self.phase, DowngraderControllerPhase::LoadingStatus);
        self.active_status_request_id = None;
        if initial_load {
            self.options.target = snapshot.default_target;
        }
        self.status = Some(snapshot);
        self.plan = None;
        self.progress = DowngraderProgress::idle();
        self.safe_error = None;
        if initial_load {
            self.phase = DowngraderControllerPhase::Ready;
            self.status_text.clear();
        } else if matches!(self.phase, DowngraderControllerPhase::Completed) {
            self.status_text = DOWNGRADER_COMPLETED_MESSAGE.to_owned();
        } else {
            self.phase = DowngraderControllerPhase::Ready;
            self.status_text.clear();
        }

        tracing::info!(
            event = "s09-downgrader-status-loaded",
            request_id,
            target = self.options.target.as_reference_str(),
            status_row_count = self.status.as_ref().map(|status| status.rows.len()).unwrap_or_default(),
            patch_enabled = self.patch_button_enabled(),
            "Downgrader status applied"
        );
        DowngraderTransitionResult::Applied
    }

    /// Applies a target selection from a typed radio value.
    pub fn set_target(&mut self, target: DowngraderTarget) -> DowngraderTransitionResult {
        if !self.controls_mutable() {
            tracing::debug!(
                event = "s09-downgrader-target-rejected",
                phase = ?self.phase,
                target = target.as_reference_str(),
                "Downgrader target change rejected in current phase"
            );
            return DowngraderTransitionResult::Rejected;
        }

        if self.options.target == target {
            return DowngraderTransitionResult::Ignored;
        }

        self.options.target = target;
        self.invalidate_plan_after_option_change("target");
        tracing::info!(
            event = "s09-downgrader-target-updated",
            target = target.as_reference_str(),
            "Downgrader target updated"
        );
        DowngraderTransitionResult::Applied
    }

    /// Applies a target selection from a UI/string value, rejecting malformed values.
    pub fn set_target_from_ui_value(&mut self, value: &str) -> DowngraderTransitionResult {
        let Some(target) = parse_target_value(value) else {
            tracing::warn!(
                event = "s09-downgrader-target-malformed",
                value,
                current_target = self.options.target.as_reference_str(),
                "Malformed Downgrader target value rejected"
            );
            return DowngraderTransitionResult::Rejected;
        };
        self.set_target(target)
    }

    /// Applies a keep-backups checkbox value.
    pub fn set_keep_backups(&mut self, keep_backups: bool) -> DowngraderTransitionResult {
        self.set_option(DOWNGRADER_KEEP_BACKUPS_KEY, keep_backups)
    }

    /// Applies a delete-deltas checkbox value.
    pub fn set_delete_deltas(&mut self, delete_deltas: bool) -> DowngraderTransitionResult {
        self.set_option(DOWNGRADER_DELETE_DELTAS_KEY, delete_deltas)
    }

    /// Applies an option value from a UI/string id, rejecting malformed option ids.
    pub fn set_option_from_ui_value(
        &mut self,
        option_id: &str,
        enabled: bool,
    ) -> DowngraderTransitionResult {
        match normalize_option_id(option_id) {
            Some(normalized) => self.set_option(normalized, enabled),
            None => {
                tracing::warn!(
                    event = "s09-downgrader-option-malformed",
                    option_id,
                    keep_backups = self.options.keep_backups,
                    delete_deltas = self.options.delete_deltas,
                    "Malformed Downgrader option value rejected"
                );
                DowngraderTransitionResult::Rejected
            }
        }
    }

    /// Handles a `Patch All` click, returning either plan work or confirmed run work.
    pub fn request_patch_all(&mut self) -> Option<DowngraderPatchWorkerRequest> {
        match self.phase {
            DowngraderControllerPhase::Ready | DowngraderControllerPhase::Completed => {
                if self.status.is_none() {
                    self.safe_error = Some(DOWNGRADER_PATCH_UNAVAILABLE_MESSAGE.to_owned());
                    self.status_text = DOWNGRADER_PATCH_UNAVAILABLE_MESSAGE.to_owned();
                    tracing::warn!(
                        event = "s09-downgrader-plan-request-rejected",
                        reason = "missing-status",
                        "Downgrader plan request rejected because status is unavailable"
                    );
                    return None;
                }

                let request_id = self.allocate_request_id();
                self.phase = DowngraderControllerPhase::Planning;
                self.active_plan_request_id = Some(request_id);
                self.latest_plan_request_id = Some(request_id);
                self.plan = None;
                self.progress = DowngraderProgress::idle();
                self.status_text = DOWNGRADER_PLANNING_MESSAGE.to_owned();
                self.safe_error = None;

                let request = DowngraderPlanWorkerRequest::new(
                    request_id,
                    self.installation.clone(),
                    self.options,
                );
                tracing::info!(
                    event = "s09-downgrader-plan-requested",
                    request_id,
                    task_id = %request.task.id,
                    target = self.options.target.as_reference_str(),
                    keep_backups = self.options.keep_backups,
                    delete_deltas = self.options.delete_deltas,
                    "Downgrader inline plan requested"
                );
                Some(DowngraderPatchWorkerRequest::PreviewPlan(request))
            }
            DowngraderControllerPhase::PlanReady => {
                let Some(plan) = self.plan.as_ref() else {
                    self.safe_error = Some(DOWNGRADER_PLAN_NOT_EXECUTABLE_MESSAGE.to_owned());
                    self.status_text = DOWNGRADER_PLAN_NOT_EXECUTABLE_MESSAGE.to_owned();
                    return None;
                };
                if !plan.can_execute {
                    self.safe_error = Some(DOWNGRADER_PLAN_NOT_EXECUTABLE_MESSAGE.to_owned());
                    self.status_text = DOWNGRADER_PLAN_NOT_EXECUTABLE_MESSAGE.to_owned();
                    tracing::warn!(
                        event = "s09-downgrader-run-request-rejected",
                        reason = "plan-not-executable",
                        plan_request_id = plan.request_id,
                        "Downgrader run request rejected because the plan cannot execute"
                    );
                    return None;
                }

                let confirmed_plan_request_id = plan.request_id;
                let request_id = self.allocate_request_id();
                self.phase = DowngraderControllerPhase::Running;
                self.active_run_request_id = Some(request_id);
                self.active_plan_request_id = None;
                self.progress = DowngraderProgress::idle();
                self.status_text = DOWNGRADER_RUNNING_MESSAGE.to_owned();
                self.safe_error = None;
                self.run_log_row_count = 0;

                let request = DowngraderRunWorkerRequest::new(
                    request_id,
                    confirmed_plan_request_id,
                    self.installation.clone(),
                    self.options,
                );
                tracing::info!(
                    event = "s09-downgrader-confirmed-run-requested",
                    request_id,
                    confirmed_plan_request_id,
                    task_id = %request.task.id,
                    target = self.options.target.as_reference_str(),
                    keep_backups = self.options.keep_backups,
                    delete_deltas = self.options.delete_deltas,
                    "Downgrader confirmed run requested"
                );
                Some(DowngraderPatchWorkerRequest::ConfirmedRun(request))
            }
            _ => {
                tracing::debug!(
                    event = "s09-downgrader-patch-request-ignored",
                    phase = ?self.phase,
                    "Downgrader Patch All request ignored in current phase"
                );
                None
            }
        }
    }

    /// Applies an inline preview plan if it belongs to the active plan request.
    pub fn plan_ready(
        &mut self,
        request_id: DowngraderRequestId,
        plan: DowngraderPreviewPlan,
    ) -> DowngraderTransitionResult {
        if !self.is_active_request(DowngraderWorkerStage::Plan, request_id)
            || plan.request_id != request_id
            || plan.options != self.options
        {
            tracing::debug!(
                event = "s09-downgrader-plan-stale-ignored",
                request_id,
                plan_request_id = plan.request_id,
                active_plan_request_id = ?self.active_plan_request_id,
                current_target = self.options.target.as_reference_str(),
                plan_target = plan.options.target.as_reference_str(),
                "Ignoring stale Downgrader plan result"
            );
            return DowngraderTransitionResult::StaleIgnored;
        }

        let row_count = plan.rows.len();
        let can_execute = plan.can_execute;
        let mutating_step_count = plan.counts.mutating_step_count;
        self.status = Some(plan.status.clone());
        self.plan = Some(plan);
        self.phase = DowngraderControllerPhase::PlanReady;
        self.active_plan_request_id = None;
        self.progress = DowngraderProgress::idle();
        self.status_text = if can_execute {
            DOWNGRADER_PLAN_READY_MESSAGE.to_owned()
        } else {
            DOWNGRADER_PLAN_NOT_EXECUTABLE_MESSAGE.to_owned()
        };
        self.safe_error = if can_execute {
            None
        } else {
            Some(DOWNGRADER_PLAN_NOT_EXECUTABLE_MESSAGE.to_owned())
        };

        tracing::info!(
            event = "s09-downgrader-plan-ready",
            request_id,
            row_count,
            can_execute,
            mutating_step_count,
            "Downgrader inline plan applied"
        );
        DowngraderTransitionResult::Applied
    }

    /// Applies a user-visible run log row if it belongs to the active run.
    pub fn run_log_row(
        &mut self,
        request_id: DowngraderRequestId,
        row: DowngraderExecutionLogRow,
    ) -> DowngraderTransitionResult {
        if !self.is_active_request(DowngraderWorkerStage::Run, request_id) {
            tracing::debug!(
                event = "s09-downgrader-log-stale-ignored",
                request_id,
                active_run_request_id = ?self.active_run_request_id,
                "Ignoring stale Downgrader log row"
            );
            return DowngraderTransitionResult::StaleIgnored;
        }

        tracing::debug!(
            event = "s09-downgrader-log-row-applied",
            request_id,
            level = row.level.as_reference_str(),
            message = row.message.as_str(),
            "Downgrader log row applied"
        );
        self.log_rows.push(row);
        self.run_log_row_count = self.run_log_row_count.saturating_add(1);
        DowngraderTransitionResult::Applied
    }

    /// Applies progress if it belongs to the active run.
    pub fn run_progress(
        &mut self,
        request_id: DowngraderRequestId,
        progress: DowngraderProgress,
    ) -> DowngraderTransitionResult {
        if !self.is_active_request(DowngraderWorkerStage::Run, request_id) {
            tracing::debug!(
                event = "s09-downgrader-progress-stale-ignored",
                request_id,
                active_run_request_id = ?self.active_run_request_id,
                "Ignoring stale Downgrader progress"
            );
            return DowngraderTransitionResult::StaleIgnored;
        }

        self.progress = progress;
        tracing::debug!(
            event = "s09-downgrader-progress-applied",
            request_id,
            progress_percent = progress.percent,
            "Downgrader progress applied"
        );
        DowngraderTransitionResult::Applied
    }

    /// Applies confirmed-run completion and schedules a status refresh request.
    pub fn run_completed(
        &mut self,
        request_id: DowngraderRequestId,
        result: DowngraderExecutionResult,
    ) -> DowngraderTransitionResult {
        if !self.is_active_request(DowngraderWorkerStage::Run, request_id)
            || result.request_id != request_id
        {
            tracing::debug!(
                event = "s09-downgrader-run-stale-ignored",
                request_id,
                result_request_id = result.request_id,
                active_run_request_id = ?self.active_run_request_id,
                "Ignoring stale Downgrader run completion"
            );
            return DowngraderTransitionResult::StaleIgnored;
        }

        if self.run_log_row_count == 0 {
            self.log_rows.extend(result.log_rows.iter().cloned());
        }
        self.phase = DowngraderControllerPhase::Completed;
        self.active_run_request_id = None;
        self.plan = None;
        self.progress = DowngraderProgress::complete();
        self.status_text = DOWNGRADER_COMPLETED_MESSAGE.to_owned();
        self.safe_error = None;
        self.run_log_row_count = 0;

        let refresh_id = self.allocate_request_id();
        self.active_status_request_id = Some(refresh_id);
        self.pending_status_refresh = Some(DowngraderStatusWorkerRequest::new(
            refresh_id,
            self.settings_snapshot.clone(),
            self.installation.clone(),
        ));

        tracing::info!(
            event = "s09-downgrader-run-completed",
            request_id,
            status_refresh_request_id = refresh_id,
            result_rows = result.rows.len(),
            result_log_rows = result.log_rows.len(),
            diagnostic_count = result.diagnostics.len(),
            patch_enabled = self.patch_button_enabled(),
            "Downgrader confirmed run completed and status refresh queued"
        );
        DowngraderTransitionResult::Applied
    }

    /// Returns and clears a pending status-refresh request created after run completion.
    pub fn take_pending_status_refresh(&mut self) -> Option<DowngraderStatusWorkerRequest> {
        self.pending_status_refresh.take()
    }

    /// Maps a worker spawn failure into a safe visible error for the active request.
    pub fn spawn_failed(
        &mut self,
        stage: DowngraderWorkerStage,
        request_id: DowngraderRequestId,
        error: WorkerSpawnError,
    ) -> DowngraderTransitionResult {
        tracing::error!(
            event = "s09-downgrader-worker-spawn-failed",
            stage = stage.label(),
            request_id,
            diagnostic = %error,
            "Downgrader worker could not be scheduled"
        );
        let safe_message = spawn_failed_message(stage);
        self.apply_safe_failure(stage, request_id, safe_message.to_owned(), Some(error.to_string()))
    }

    /// Applies an owned worker event if it carries a matching Downgrader payload.
    pub fn handle_worker_event(&mut self, event: WorkerEvent) -> DowngraderTransitionResult {
        let task = event.task;
        let status = event.status;
        match event.payload {
            WorkerPayload::Downgrader(payload) => {
                if !payload_matches_task(&payload, &task.id) {
                    tracing::debug!(
                        event = "s09-downgrader-payload-task-mismatch",
                        task_id = %task.id,
                        payload_request_id = payload.request_id(),
                        payload_stage = payload.stage().label(),
                        "Downgrader payload task id mismatch ignored"
                    );
                    return DowngraderTransitionResult::Ignored;
                }
                self.handle_downgrader_payload(payload)
            }
            WorkerPayload::Error(failure) if status == WorkerTaskStatus::Failed => {
                match downgrader_stage_and_request_id_from_task_id(&task.id) {
                    Some((stage, request_id)) => self.worker_failed(stage, request_id, failure),
                    None => DowngraderTransitionResult::Ignored,
                }
            }
            WorkerPayload::None if status == WorkerTaskStatus::Running => {
                match downgrader_stage_and_request_id_from_task_id(&task.id) {
                    Some((stage, request_id)) => self.worker_started(stage, request_id),
                    None => DowngraderTransitionResult::Ignored,
                }
            }
            _ => DowngraderTransitionResult::Ignored,
        }
    }

    /// Applies a worker failure with safe text separated from diagnostics.
    pub fn worker_failed(
        &mut self,
        stage: DowngraderWorkerStage,
        request_id: DowngraderRequestId,
        failure: WorkerFailure,
    ) -> DowngraderTransitionResult {
        self.apply_safe_failure(
            stage,
            request_id,
            failure.safe_message().to_owned(),
            failure.diagnostic().map(str::to_owned),
        )
    }

    /// Handles a close or Escape request, blocking only during confirmed runs.
    pub fn request_close(&mut self) -> DowngraderCloseResult {
        if matches!(self.phase, DowngraderControllerPhase::Running) {
            tracing::warn!(
                event = "s09-downgrader-close-blocked",
                active_run_request_id = ?self.active_run_request_id,
                "Downgrader close request blocked while a run is active"
            );
            return DowngraderCloseResult::Blocked;
        }

        let next_request_id = self.next_request_id;
        *self = Self::new();
        self.next_request_id = next_request_id;
        tracing::info!(
            event = "s09-downgrader-closed",
            next_request_id = self.next_request_id,
            "Downgrader modal closed"
        );
        DowngraderCloseResult::Closed
    }

    fn set_option(&mut self, option_id: &str, enabled: bool) -> DowngraderTransitionResult {
        if !self.controls_mutable() {
            tracing::debug!(
                event = "s09-downgrader-option-rejected",
                option_id,
                enabled,
                phase = ?self.phase,
                "Downgrader option change rejected in current phase"
            );
            return DowngraderTransitionResult::Rejected;
        }

        let changed = match option_id {
            DOWNGRADER_KEEP_BACKUPS_KEY => {
                let changed = self.options.keep_backups != enabled;
                self.options.keep_backups = enabled;
                changed
            }
            DOWNGRADER_DELETE_DELTAS_KEY => {
                let changed = self.options.delete_deltas != enabled;
                self.options.delete_deltas = enabled;
                changed
            }
            _ => return DowngraderTransitionResult::Rejected,
        };

        if !changed {
            return DowngraderTransitionResult::Ignored;
        }

        self.invalidate_plan_after_option_change(option_id);
        tracing::info!(
            event = "s09-downgrader-option-updated",
            option_id,
            enabled,
            keep_backups = self.options.keep_backups,
            delete_deltas = self.options.delete_deltas,
            "Downgrader option updated"
        );
        DowngraderTransitionResult::Applied
    }

    fn controls_mutable(&self) -> bool {
        self.status.is_some()
            && matches!(
                self.phase,
                DowngraderControllerPhase::Ready
                    | DowngraderControllerPhase::PlanReady
                    | DowngraderControllerPhase::Completed
                    | DowngraderControllerPhase::SafeError
            )
    }

    fn invalidate_plan_after_option_change(&mut self, reason: &str) {
        self.plan = None;
        self.active_plan_request_id = None;
        self.safe_error = None;
        if self.status.is_some() {
            self.phase = DowngraderControllerPhase::Ready;
            self.status_text.clear();
        }
        tracing::debug!(
            event = "s09-downgrader-plan-invalidated",
            reason,
            "Downgrader inline plan invalidated after option change"
        );
    }

    fn worker_started(
        &mut self,
        stage: DowngraderWorkerStage,
        request_id: DowngraderRequestId,
    ) -> DowngraderTransitionResult {
        if !self.is_active_request(stage, request_id) {
            tracing::debug!(
                event = "s09-downgrader-worker-start-stale-ignored",
                stage = stage.label(),
                request_id,
                active_status_request_id = ?self.active_status_request_id,
                active_plan_request_id = ?self.active_plan_request_id,
                active_run_request_id = ?self.active_run_request_id,
                "Ignoring stale Downgrader worker start"
            );
            return DowngraderTransitionResult::StaleIgnored;
        }

        match stage {
            DowngraderWorkerStage::Status => {
                if !matches!(self.phase, DowngraderControllerPhase::Completed) {
                    self.phase = DowngraderControllerPhase::LoadingStatus;
                    self.status_text = DOWNGRADER_LOADING_STATUS_MESSAGE.to_owned();
                }
            }
            DowngraderWorkerStage::Plan => {
                self.phase = DowngraderControllerPhase::Planning;
                self.status_text = DOWNGRADER_PLANNING_MESSAGE.to_owned();
            }
            DowngraderWorkerStage::Run => {
                self.phase = DowngraderControllerPhase::Running;
                self.status_text = DOWNGRADER_RUNNING_MESSAGE.to_owned();
            }
        }
        tracing::debug!(
            event = "s09-downgrader-worker-started",
            stage = stage.label(),
            request_id,
            "Downgrader worker start applied"
        );
        DowngraderTransitionResult::Applied
    }

    fn handle_downgrader_payload(
        &mut self,
        payload: DowngraderWorkerPayload,
    ) -> DowngraderTransitionResult {
        match payload {
            DowngraderWorkerPayload::StatusLoaded {
                request_id,
                snapshot,
            } => self.status_loaded(request_id, *snapshot),
            DowngraderWorkerPayload::PlanReady { request_id, plan } => {
                self.plan_ready(request_id, *plan)
            }
            DowngraderWorkerPayload::LogRow { request_id, row } => {
                self.run_log_row(request_id, row)
            }
            DowngraderWorkerPayload::Progress {
                request_id,
                progress,
            } => self.run_progress(request_id, progress),
            DowngraderWorkerPayload::RunCompleted { request_id, result } => {
                self.run_completed(request_id, *result)
            }
            DowngraderWorkerPayload::SafeFailure {
                request_id,
                stage,
                safe_message,
                diagnostic,
            } => self.apply_safe_failure(stage, request_id, safe_message, diagnostic),
        }
    }

    fn apply_safe_failure(
        &mut self,
        stage: DowngraderWorkerStage,
        request_id: DowngraderRequestId,
        safe_message: String,
        diagnostic: Option<String>,
    ) -> DowngraderTransitionResult {
        if !self.is_active_request(stage, request_id) {
            tracing::debug!(
                event = "s09-downgrader-failure-stale-ignored",
                stage = stage.label(),
                request_id,
                active_status_request_id = ?self.active_status_request_id,
                active_plan_request_id = ?self.active_plan_request_id,
                active_run_request_id = ?self.active_run_request_id,
                "Ignoring stale Downgrader failure"
            );
            return DowngraderTransitionResult::StaleIgnored;
        }

        match stage {
            DowngraderWorkerStage::Status => self.active_status_request_id = None,
            DowngraderWorkerStage::Plan => self.active_plan_request_id = None,
            DowngraderWorkerStage::Run => {
                self.active_run_request_id = None;
                self.run_log_row_count = 0;
            }
        }
        self.phase = DowngraderControllerPhase::SafeError;
        self.status_text = safe_message.clone();
        self.safe_error = Some(safe_message.clone());
        self.progress = DowngraderProgress::idle();
        self.pending_status_refresh = None;
        self.log_rows.push(DowngraderExecutionLogRow::new(
            DowngraderLogLevel::Bad,
            safe_message.clone(),
        ));
        tracing::error!(
            event = "s09-downgrader-worker-failed",
            stage = stage.label(),
            request_id,
            safe_message = safe_message.as_str(),
            diagnostic = diagnostic.as_deref().unwrap_or(""),
            close_enabled = self.close_enabled(),
            "Downgrader worker failure applied"
        );
        DowngraderTransitionResult::Applied
    }

    fn is_active_request(
        &self,
        stage: DowngraderWorkerStage,
        request_id: DowngraderRequestId,
    ) -> bool {
        match stage {
            DowngraderWorkerStage::Status => self.active_status_request_id == Some(request_id),
            DowngraderWorkerStage::Plan => self.active_plan_request_id == Some(request_id),
            DowngraderWorkerStage::Run => self.active_run_request_id == Some(request_id),
        }
    }

    fn allocate_request_id(&mut self) -> DowngraderRequestId {
        let request_id = self.next_request_id;
        self.next_request_id = self.next_request_id.saturating_add(1);
        request_id
    }
}

/// Builds worker metadata for a Downgrader status request.
pub fn downgrader_status_task(request_id: DowngraderRequestId) -> WorkerTask {
    WorkerTask::new(
        format!("{DOWNGRADER_STATUS_TASK_PREFIX}{request_id}"),
        WorkerTaskKind::Patch,
    )
    .with_label("Load Downgrader status")
}

/// Builds worker metadata for a Downgrader preview-plan request.
pub fn downgrader_plan_task(request_id: DowngraderRequestId) -> WorkerTask {
    WorkerTask::new(
        format!("{DOWNGRADER_PLAN_TASK_PREFIX}{request_id}"),
        WorkerTaskKind::Patch,
    )
    .with_label("Prepare Downgrader plan")
}

/// Builds worker metadata for a Downgrader confirmed run.
pub fn downgrader_run_task(request_id: DowngraderRequestId) -> WorkerTask {
    WorkerTask::new(
        format!("{DOWNGRADER_RUN_TASK_PREFIX}{request_id}"),
        WorkerTaskKind::Patch,
    )
    .with_label("Run Downgrader")
}

/// Converts a status snapshot into the Downgrader worker payload shape.
pub fn downgrader_status_loaded_payload(
    request_id: DowngraderRequestId,
    snapshot: DowngraderStatusSnapshot,
)

